#!/usr/bin/env node
/**
 * Print a canonical https://github.com/owner/repo URL from SSH or HTTPS input.
 *
 * Usage: node normalize-github-repo-url.mjs <repo-url>
 */
const u = (process.argv[2] ?? process.argv[1] ?? '').trim();
if (!u) {
  process.stderr.write('normalize-github-repo-url: repo URL is required\n');
  process.exit(1);
}
if (u.startsWith('git@')) {
  const m = u.match(/^git@github\.com:([^/]+)\/(.+?)(\.git)?$/i);
  if (m) {
    process.stdout.write(
      `https://github.com/${m[1]}/${m[2].replace(/\.git$/, '')}`,
    );
    process.exit(0);
  }
}
try {
  const url = new URL(u);
  const path = url.pathname.replace(/^\/+/, '').replace(/\.git$/, '');
  const parts = path.split('/').filter(Boolean);
  if (parts.length >= 2) {
    process.stdout.write(`https://github.com/${parts[0]}/${parts[1]}`);
  } else {
    process.stdout.write(u);
  }
} catch {
  process.stdout.write(u);
}

